function fmt(n,c){c=c||"OMR";var v=typeof n==="number"?n:0;var s={OMR:" ر.ع",AED:" د.إ",SAR:" ر.س"};return(c==="USD"?"$":"")+v.toFixed(c==="OMR"?3:2)+(s[c]||"");}
function fD(d){return new Date(d).toLocaleDateString("en-GB",{year:"numeric",month:"short",day:"numeric"});}
function iTotal(inv){var s=0;for(var i=0;i<inv.items.length;i++)s+=inv.items[i].qty*inv.items[i].price;return s;}
function iVat(inv){return iTotal(inv)*VAT;}
function iGrand(inv){return iTotal(inv)*(1+VAT);}
function today(){return new Date().toISOString().slice(0,10);}
function uid(){return Math.random().toString(36).slice(2,8);}
function maxId(arr){var m=0;for(var i=0;i<arr.length;i++){if(arr[i].id>m)m=arr[i].id;}return m;}

/* ── Build CSV/JSON strings ── */
function buildCSV(headers,rows){
  var lines=[headers.join(",")];
  for(var i=0;i<rows.length;i++){var cells=[];for(var j=0;j<rows[i].length;j++)cells.push('"'+String(rows[i][j]).replace(/"/g,'""')+'"');lines.push(cells.join(","));}
  return lines.join("\n");
}
function buildJSON(data){return JSON.stringify(data,null,2);}

/* ── Download via data URI (sandbox-safe, no Blob needed) ── */
function triggerDownload(filename,content,mime){
  try{
    var uri="data:"+mime+";charset=utf-8,"+encodeURIComponent(content);
    var a=document.createElement("a");
    a.href=uri;
    a.download=filename;
    a.style.display="none";
    document.body.appendChild(a);
    a.click();
    setTimeout(function(){document.body.removeChild(a);},100);
    return true;
  }catch(e){return false;}
}

