/* ── Export Modal: Download file + Copy to Clipboard ── */
function ExportModal(p){
  var [copied,setCopied]=useState(false);
  var [dlOk,setDlOk]=useState(false);
  var mime=p.type==="json"?"application/json":"text/csv";

  function doCopy(){
    try{
      navigator.clipboard.writeText(p.content).then(function(){setCopied(true);setTimeout(function(){setCopied(false);},2000);});
    }catch(e){
      var ta=document.createElement("textarea");ta.value=p.content;ta.style.cssText="position:fixed;left:-9999px;top:-9999px";document.body.appendChild(ta);ta.focus();ta.select();
      try{document.execCommand("copy");setCopied(true);setTimeout(function(){setCopied(false);},2000);}catch(ex){}
      document.body.removeChild(ta);
    }
  }

  function doDownload(){
    var ok=triggerDownload(p.filename,p.content,mime);
    setDlOk(true);setTimeout(function(){setDlOk(false);},2000);
  }

  if(!p.open)return null;
  var dataHref="data:"+mime+";charset=utf-8,"+encodeURIComponent(p.content);

  return <div onClick={p.onClose} style={{position:"fixed",inset:0,background:"rgba(0,0,0,.7)",zIndex:1100,display:"flex",alignItems:"center",justifyContent:"center",backdropFilter:"blur(4px)"}}>
    <div onClick={function(e){e.stopPropagation();}} style={{background:C.card,border:"1px solid "+C.brd,borderRadius:16,padding:28,width:640,maxWidth:"92vw",maxHeight:"85vh",display:"flex",flexDirection:"column",boxShadow:"0 25px 60px rgba(0,0,0,.5)"}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
        <div>
          <h3 style={{fontSize:17,fontWeight:700,color:C.txt,margin:0}}>{p.filename}</h3>
          <span style={{fontSize:11,color:C.mut}}>{p.type==="csv"?"CSV Spreadsheet":"JSON Data"}</span>
        </div>
        <button type="button" onClick={p.onClose} style={{background:"none",border:"none",cursor:"pointer",color:C.mut,padding:4}}><Ic d={icons.x} s={18}/></button>
      </div>
      <div style={{flex:1,overflow:"auto",marginBottom:16}}>
        <pre style={{background:C.bg,border:"1px solid "+C.brd,borderRadius:10,padding:16,fontSize:11,color:C.txt,lineHeight:1.5,margin:0,whiteSpace:"pre-wrap",wordBreak:"break-all",maxHeight:300,overflow:"auto",fontFamily:"'SF Mono','Fira Code',monospace"}}>{p.content}</pre>
      </div>
      <div style={{display:"flex",gap:8,justifyContent:"flex-end",flexWrap:"wrap"}}>
        <Btn v="ghost" onClick={p.onClose}>Close</Btn>
        <Btn v={copied?"success":"secondary"} onClick={doCopy}>
          <Ic d={copied?icons.check:icons.clip} s={14} c={copied?"#fff":C.txt}/>
          {copied?"Copied!":"Copy to Clipboard"}
        </Btn>
        <a href={dataHref} download={p.filename} style={{textDecoration:"none"}}>
          <Btn v={dlOk?"success":"primary"} onClick={function(){setDlOk(true);setTimeout(function(){setDlOk(false);},2000);}}>
            <Ic d={dlOk?icons.check:icons.dl} s={14} c="#fff"/>
            {dlOk?"Downloaded!":"Download "+p.filename}
          </Btn>
        </a>
      </div>
    </div>
  </div>;
}

